namespace Forge.Api.Data.TrainingContent;

public class MaintenanceTraining : TrainingContentBase
{
    public MaintenanceTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Predictive Maintenance Overview",
            Slug = "maintenance-overview",
            Summary = "What predictive maintenance is, how failure predictions and confidence work, severity and the prediction lifecycle, and how to acknowledge, schedule, resolve, or dismiss predictions.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/maintenance/predictions"]""",
            Tags = """["maintenance","assets","predictive"]""",
            ContentJson = """{"body":"## Predictive Maintenance Overview\n\nThe Predictive Maintenance module is a monitoring-and-response dashboard. Instead of waiting for a machine to break or running maintenance on a rigid calendar, the system watches your equipment, forecasts likely failures before they happen, and gives you a prioritized list of what to act on. The goal is simple: fix the right thing at the right time, and prevent unplanned downtime.\n\nThe page lives at the Predictions route and is intentionally **read-only for the creation of predictions** — you don't add predictions by hand. They are generated by a model from equipment data. What you *do* on this page is respond: acknowledge a prediction, schedule preventive maintenance against it, resolve it once the work is done, or flag it as a false positive.\n\n### What Is a Prediction?\n\nA **prediction** is the model's forecast that a work center (asset) will experience a specific kind of failure by a certain date. Each prediction carries:\n- The **Work Center** (asset) it applies to\n- A **Prediction Type** — the nature of the predicted failure (e.g., a bearing or coolant issue)\n- A **Severity** — Critical, High, Medium, or Low\n- A **Confidence %** — how sure the model is that the prediction is correct\n- A **Predicted Failure** date and time — when the failure is expected\n- A **Status** — where the prediction sits in its lifecycle\n\n### Confidence and Severity\n\nThese two values work together to help you triage:\n- **Confidence %** is the model's certainty (0–100%). A high-confidence prediction is one the model is sure about; a low-confidence one is more speculative. Use confidence to decide how much to trust a prediction.\n- **Severity** is about consequence and urgency. **Critical** means imminent failure risk needing urgent attention; **High** means failure is likely within days; **Medium** means a moderate risk where preventive action is sensible; **Low** means a low risk worth monitoring.\n\nA Critical prediction with high confidence is the kind of item you act on first.\n\n### The Prediction Lifecycle\n\nPredictions move through a defined set of statuses:\n\n1. **Predicted** — The initial state. The model has flagged a likely failure and it needs your attention. This is an open item.\n2. **Acknowledged** — You have seen and accepted the prediction. It is still open, but now it's on the radar and waiting for maintenance to be scheduled.\n3. **MaintenanceScheduled** — A preventive maintenance job has been created and linked to the prediction. The work to prevent the failure is planned.\n4. **Resolved** — The maintenance was completed and you've closed the prediction out with resolution notes. This is a terminal (closed) state.\n5. **FalsePositive** — You determined the prediction was wrong and marked it so, with a reason. Terminal.\n6. **Expired** — The predicted failure date passed and the prediction is no longer relevant. Terminal.\n\nThe first three states are *open*; the last three are *closed*. The default filter on the page shows only open predictions so you focus on what still needs action.\n\n### The KPI Strip\n\nAt the top of the page, a row of metric cards summarizes the overall picture: how many predictions are active, how many are Critical (highlighted), how many are pending acknowledgment, how many have maintenance scheduled, the model's overall accuracy, and the estimated downtime prevented in hours. These give leadership a one-glance health read of the predictive program itself.\n\n### Responding to a Prediction\n\nEach prediction row offers actions that depend on its status:\n- **Acknowledge** — Available on a Predicted item. Marks that you've seen it; moves it to Acknowledged.\n- **Schedule Maintenance** — Available on Predicted or Acknowledged items. Creates and links a preventive maintenance job; moves the prediction to MaintenanceScheduled.\n- **Resolve** — Available on any open item. Opens a dialog where you enter resolution notes, then closes the prediction as Resolved.\n- **False Positive** — Available on any open item. Opens a dialog where you enter a reason, then closes the prediction as FalsePositive.\n\nResolving and marking-false both record notes, which (along with whether the prediction proved accurate) feed the model's accuracy tracking over time.\n\n### How Predictions Connect to Other Features\n\n**Assets / Work Centers:** Every prediction references the work center it concerns, tying the maintenance view to the equipment master and to scheduling.\n\n**Preventive Maintenance Jobs:** Scheduling maintenance creates a linked PM job — the actual planned work that addresses the predicted failure.\n\n**Accuracy Feedback Loop:** When you resolve a prediction or mark it false, you're telling the system whether the prediction was right. The overall model accuracy KPI reflects this feedback so the program improves over time.\n\n### When to Use Predictive Maintenance\n\n- When you want to catch equipment failures before they cause unplanned downtime\n- When triaging which assets need attention first — sort by severity and confidence\n- When you've reviewed a prediction and want to put it on the radar — acknowledge it\n- When you're ready to plan the fix — schedule maintenance to create a linked PM job\n- When the work is done — resolve the prediction with notes\n- When the model got it wrong — mark it a false positive so accuracy tracking learns","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Predictive Maintenance — Guided Tour",
