            Summary = "A guided tour of the predictions page: the KPI strip, severity and status filters, the predictions table, and the acknowledge, schedule, resolve, and false-positive actions.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/maintenance/predictions"]""",
            Tags = """["maintenance","assets","predictive","walkthrough"]""",
            ContentJson = """{"appRoute":"/maintenance/predictions","startButtonLabel":"Tour Predictive Maintenance","steps":[{"element":".kpi-strip","popover":{"title":"Predictive Maintenance KPIs","description":"This strip of cards summarizes the whole program at a glance: active predictions, Critical predictions, items pending acknowledgment, maintenance scheduled, the model's overall accuracy, and the estimated downtime prevented in hours. It's the one-glance health read of your predictive maintenance.","side":"bottom"}},{"element":".kpi-strip","popover":{"title":"Critical Predictions","description":"Within this strip, the highlighted Critical card calls out how many predictions are Critical severity — imminent failure risk that needs urgent attention. When that number is non-zero, those items should be your first stop in the table below.","side":"bottom"}},{"element":"app-toolbar","popover":{"title":"Filters","description":"Use the Severity and Status filters to focus the list. By default the Status filter is set to 'open' so you only see predictions that still need action — Predicted, Acknowledged, or MaintenanceScheduled — and not the closed ones.","side":"bottom"}},{"element":"app-toolbar app-select","popover":{"title":"Severity & Status Filters","description":"The first dropdown filters by Severity (Critical, High, Medium, Low, or all). The second filters by Status (open, a specific status, or all). Combine them to drill into, say, all Critical predictions awaiting acknowledgment.","side":"bottom"}},{"element":"[tableId='maintenance-predictions']","popover":{"title":"Predictions Table","description":"Each row is one prediction: the work center (asset), prediction type, severity (color chip), confidence %, predicted failure date and time, status (color chip), and the response actions. Click a column header to sort — by severity or predicted failure date, for example, to surface what's most urgent.","side":"top"}},{"element":"[tableId='maintenance-predictions']","popover":{"title":"Respond to a Prediction","description":"Each row's Actions column carries icons that depend on the prediction's status. Acknowledge (check_circle) confirms you've seen a Predicted item. Schedule (schedule) creates a linked preventive maintenance job. Resolve (task_alt) and False Positive (cancel) each open a dialog for notes and close the prediction out.","side":"top"}},{"element":".toolbar__hint","popover":{"title":"Tracking Over Time","description":"This hint reminds you how the data behaves and what tracking the predictions over time gives you. As you acknowledge, schedule, resolve, and dismiss predictions, that feedback flows into the model-accuracy KPI so the program keeps improving.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Predictive Maintenance Field Reference",
            Slug = "maintenance-field-reference",
            Summary = "Complete reference for every KPI, filter, table column, severity, status, action, and dialog field in the Predictive Maintenance module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/maintenance/predictions"]""",
            Tags = """["maintenance","assets","predictive","reference"]""",
            ContentJson = """{"title":"Predictive Maintenance Field Reference","groups":[{"heading":"KPI Strip (Top of Page)","items":[{"label":"Active Predictions","value":"Count of predictions that are currently open (not closed)."},{"label":"Critical","value":"Count of Critical-severity predictions. Shown on a highlighted card with a red accent."},{"label":"Pending Acknowledgment","value":"Count of predictions still in the Predicted state, awaiting acknowledgment."},{"label":"Maintenance Scheduled","value":"Count of predictions with a linked preventive maintenance job."},{"label":"Model Accuracy","value":"The model's overall accuracy across all predictions, shown as a percentage."},{"label":"Downtime Prevented","value":"Estimated hours of downtime prevented by acting on predictions, shown in hours."}]},{"heading":"Filters","items":[{"label":"Severity","value":"Dropdown. Options: all, Critical, High, Medium, Low. Filters the table to the chosen severity."},{"label":"Status","value":"Dropdown. Options: all, open, Predicted, Acknowledged, MaintenanceScheduled, Resolved, FalsePositive, Expired. Defaults to 'open', which shows only predictions that still need action."}]},{"heading":"Severity Levels","items":[{"label":"Critical (error chip)","value":"Immediate failure risk; requires urgent attention. Act on these first."},{"label":"High (warning chip)","value":"High likelihood of failure within days."},{"label":"Medium (info chip)","value":"Moderate failure risk; preventive action recommended."},{"label":"Low (muted chip)","value":"Low failure risk; monitor for degradation."}]},{"heading":"Prediction Statuses (Lifecycle)","items":[{"label":"Predicted (warning chip)","value":"Initial state. The model flagged a likely failure and it needs attention. Open. Can be acknowledged, scheduled, resolved, or marked false positive."},{"label":"Acknowledged (info chip)","value":"You've seen and accepted the prediction; not yet scheduled. Open. Can be scheduled, resolved, or marked false positive."},{"label":"MaintenanceScheduled (primary chip)","value":"A preventive maintenance job is created and linked. Open. Can be resolved or marked false positive."},{"label":"Resolved (success chip)","value":"Maintenance completed; closed with resolution notes. Terminal."},{"label":"FalsePositive (muted chip)","value":"Determined incorrect and marked false with a reason. Terminal."},{"label":"Expired (muted chip)","value":"The predicted failure date passed and the prediction is no longer relevant. Terminal."}]},{"heading":"Table Columns","items":[{"label":"Work Center","value":"Sortable. The asset / work center the prediction applies to. Plain text."},{"label":"Type","value":"Sortable. The prediction type — the nature of the predicted failure. Width 160px."},{"label":"Severity","value":"Sortable. Color-coded chip (Critical / High / Medium / Low). Width 110px."},{"label":"Confidence %","value":"Sortable. The model's certainty, formatted as a percentage (e.g., 92.5%). Number, right-aligned, width 110px."},{"label":"Predicted Failure","value":"Sortable. Predicted failure date and time, formatted MM/dd/yyyy hh:mm. Date, width 160px."},{"label":"Status","value":"Sortable. Color-coded lifecycle chip. Width 140px."},{"label":"Actions","value":"Row response buttons (Acknowledge / Schedule / Resolve / False Positive), shown based on status. Right-aligned, width 180px."}]},{"heading":"Row Actions (Status-Dependent)","items":[{"label":"Acknowledge (check_circle icon)","value":"Available on a Predicted item. Marks that you've seen it and moves the status to Acknowledged."},{"label":"Schedule Maintenance (schedule icon)","value":"Available on Predicted or Acknowledged items. Creates and links a preventive maintenance job; moves the status to MaintenanceScheduled."},{"label":"Resolve (task_alt icon)","value":"Available on any open item. Opens the resolve dialog for notes, then closes the prediction as Resolved."},{"label":"False Positive (cancel icon)","value":"Available on any open item. Opens the false-positive dialog for a reason, then closes the prediction as FalsePositive."}]},{"heading":"Resolve / False-Positive Dialog","items":[{"label":"Title","value":"Changes by mode: 'Resolve Prediction' when resolving, 'Mark as False Positive' when dismissing."},{"label":"Notes (required)","value":"Textarea. The resolution notes (resolve mode) or the reason it was a false positive. Required, max 2000 characters. data-testid: resolve-notes"},{"label":"Cancel","value":"Closes the dialog without saving."},{"label":"Confirm","value":"Submits the resolution / false-positive with the notes and closes the prediction. Disabled while the form is invalid; a validation button surfaces violations. data-testid: resolve-confirm-btn"}]},{"heading":"Key Concepts","items":[{"label":"Prediction","value":"The model's forecast that a specific work center will experience a specific kind of failure by a certain date."},{"label":"Confidence %","value":"How certain the model is that the prediction is correct (0–100%). Use it to decide how much to trust a prediction."},{"label":"Severity","value":"How consequential and urgent the predicted failure is (Critical / High / Medium / Low). Use it to decide what to act on first."},{"label":"Open vs Closed","value":"Predicted, Acknowledged, and MaintenanceScheduled are open (need action); Resolved, FalsePositive, and Expired are closed (terminal)."},{"label":"Preventive Maintenance (PM) Job","value":"The planned maintenance work that scheduling creates and links to a prediction to prevent the forecasted failure."},{"label":"Accuracy Feedback","value":"Resolving or dismissing a prediction tells the system whether it was right, which feeds the overall model-accuracy KPI."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Predictive Maintenance Knowledge Check",
            Slug = "maintenance-quiz",
            Summary = "Test your knowledge of the Predictive Maintenance module: predictions, confidence, severity, the status lifecycle, and the acknowledge/schedule/resolve/false-positive actions.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/maintenance/predictions"]""",
            Tags = """["maintenance","assets","predictive","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"mn1","text":"How are predictions created in the Predictive Maintenance module?","options":[{"id":"a","text":"A user clicks a 'New Prediction' button and fills out a form"},{"id":"b","text":"They are generated by a model from equipment data — the page is read-only for creation; you respond to predictions, you don't add them by hand","isCorrect":true},{"id":"c","text":"They are imported from purchase orders"},{"id":"d","text":"They are entered by the customer through a portal"}],"explanation":"You don't add predictions manually. The model generates them from equipment data. The page is a monitoring-and-response dashboard — what you do is acknowledge, schedule maintenance, resolve, or mark false-positive."},{"id":"mn2","text":"What does the Confidence % on a prediction represent?","options":[{"id":"a","text":"The percentage of the asset's useful life remaining"},{"id":"b","text":"How certain the model is that the prediction is correct (0–100%)","isCorrect":true},{"id":"c","text":"The percentage discount on the maintenance cost"},{"id":"d","text":"How many similar assets have failed this year"}],"explanation":"Confidence % is the model's certainty that the prediction is correct, from 0 to 100%. A high-confidence prediction is one the model is sure about; use confidence to decide how much to trust a prediction when triaging."},{"id":"mn3","text":"Which severity means imminent failure risk requiring urgent attention?","options":[{"id":"a","text":"Low"},{"id":"b","text":"Medium"},{"id":"c","text":"Critical","isCorrect":true},{"id":"d","text":"High"}],"explanation":"Critical means immediate failure risk requiring urgent attention — act on these first. High means failure is likely within days, Medium is a moderate risk where preventive action is recommended, and Low is a low risk worth monitoring."},{"id":"mn4","text":"What is the correct prediction lifecycle from creation to a completed fix?","options":[{"id":"a","text":"Open → Working → Done"},{"id":"b","text":"Predicted → Acknowledged → MaintenanceScheduled → Resolved","isCorrect":true},{"id":"c","text":"Draft → Sent → Accepted → Closed"},{"id":"d","text":"New → Triaged → Escalated → Archived"}],"explanation":"A prediction starts as Predicted, becomes Acknowledged when you accept it, MaintenanceScheduled when a PM job is created and linked, and Resolved once the work is done and you close it with notes. (FalsePositive and Expired are the other two terminal states.)"},{"id":"mn5","text":"By default, the Status filter on the predictions page is set to 'open'. What does that show?","options":[{"id":"a","text":"Every prediction ever made"},{"id":"b","text":"Only predictions that still need action — Predicted, Acknowledged, and MaintenanceScheduled — excluding the closed ones","isCorrect":true},{"id":"c","text":"Only Critical-severity predictions"},{"id":"d","text":"Only predictions that were marked false positive"}],"explanation":"The default 'open' filter shows the three open states (Predicted, Acknowledged, MaintenanceScheduled) and hides the closed/terminal ones (Resolved, FalsePositive, Expired), so you focus on what still needs action."},{"id":"mn6","text":"You've reviewed a Predicted item and want to put it on the radar without scheduling work yet. Which action do you take?","options":[{"id":"a","text":"Resolve"},{"id":"b","text":"Acknowledge — it moves the status to Acknowledged","isCorrect":true},{"id":"c","text":"False Positive"},{"id":"d","text":"Delete the prediction"}],"explanation":"Acknowledge (the check_circle icon) is available on a Predicted item. It marks that you've seen and accepted the prediction and moves it to Acknowledged — still open, but now on the radar and waiting for maintenance to be scheduled."},{"id":"mn7","text":"What happens when you click Schedule Maintenance on a prediction?","options":[{"id":"a","text":"The prediction is permanently deleted"},{"id":"b","text":"A preventive maintenance job is created and linked to the prediction, and the status moves to MaintenanceScheduled","isCorrect":true},{"id":"c","text":"The asset is immediately taken offline"},{"id":"d","text":"An invoice is generated for the repair"}],"explanation":"Schedule Maintenance (the schedule icon, available on Predicted or Acknowledged items) creates and links a preventive maintenance job — the planned work that addresses the forecasted failure — and moves the prediction to MaintenanceScheduled."},{"id":"mn8","text":"You determine that a prediction was wrong. What do you do, and what is required?","options":[{"id":"a","text":"Click False Positive; no further input is needed"},{"id":"b","text":"Click False Positive, which opens a dialog where you enter a required reason (notes) before confirming; the prediction closes as FalsePositive","isCorrect":true},{"id":"c","text":"Change the severity to Low"},{"id":"d","text":"Wait for it to Expire on its own"}],"explanation":"False Positive (the cancel icon) opens a dialog with a required Notes field (max 2000 characters). After you enter the reason and confirm, the prediction is closed as FalsePositive. This feedback helps the overall model-accuracy tracking."},{"id":"mn9","text":"What is the difference between Severity and Confidence when triaging a prediction?","options":[{"id":"a","text":"They are the same thing measured on different scales"},{"id":"b","text":"Severity is about the consequence and urgency of the failure; Confidence is about how sure the model is the prediction is correct","isCorrect":true},{"id":"c","text":"Severity is set by the user; Confidence is set by the customer"},{"id":"d","text":"Severity applies to the asset; Confidence applies to the work order"}],"explanation":"Severity tells you how consequential and urgent a failure is (Critical/High/Medium/Low), while Confidence tells you how certain the model is the prediction is right. A Critical, high-confidence prediction is the kind of item you act on first."},{"id":"mn10","text":"When you resolve a prediction, what is required in the resolve dialog?","options":[{"id":"a","text":"Nothing — you just click Confirm"},{"id":"b","text":"Resolution notes (a required Notes textarea, max 2000 characters)","isCorrect":true},{"id":"c","text":"A photo upload of the repaired part"},{"id":"d","text":"The cost of the maintenance in dollars"}],"explanation":"The Resolve action opens a dialog with a required Notes field (max 2000 characters). You enter the resolution notes and confirm; the prediction closes as Resolved. The Confirm button stays disabled until the notes are filled in."},{"id":"mn11","text":"Which KPI card is highlighted with a red accent to call attention to it?","options":[{"id":"a","text":"Model Accuracy"},{"id":"b","text":"Downtime Prevented"},{"id":"c","text":"Critical predictions","isCorrect":true},{"id":"d","text":"Active Predictions"}],"explanation":"The Critical card is rendered on a highlighted card with a red accent because Critical predictions carry imminent failure risk. When that number is non-zero, those items should be your first stop in the table."},{"id":"mn12","text":"How does resolving or dismissing predictions help the system over time?","options":[{"id":"a","text":"It has no lasting effect"},{"id":"b","text":"It tells the system whether the prediction was right, which feeds the overall model-accuracy KPI so the program improves","isCorrect":true},{"id":"c","text":"It automatically increases every work center's capacity"},{"id":"d","text":"It deletes the asset from the system"}],"explanation":"Resolving a prediction or marking it false provides accuracy feedback — the system learns whether the prediction proved correct. That feedback is reflected in the overall model-accuracy KPI, so the predictive program gets better over time."}]}"""
        });

        Log.Information("Seeded Predictive Maintenance training modules");
    }
}
